{
  "Cargo.toml": "[package]
name = "neighbor_lists"
version = "0.1.0"
edition = "2024"

[dependencies]
rayon = "1.10"
",
  "main.rs": "use rayon::prelude::*;

#[derive(Debug, Default, Clone)]
struct B {
    r: Vec<f64>,
    v: Vec<f64>,
    f: Vec<f64>,
    nb: Vec<usize>,
}

impl B {
    pub fn criterion(&self, other: &B) -> f64 {
        let dx = self.r[0] - other.r[0];
        let dy = self.r[1] - other.r[1];
        let dz = self.r[2] - other.r[2];
        dx * dx + dy * dy + dz * dz
    }
}

#[derive(Debug, Default, Clone)]
struct A {
    elems: Vec<B>,
    cutoff: f64,
}

impl A {
    pub fn get_nelems(&self) -> usize {
        self.elems.len()
    }

    /// 1) Safe, no `unsafe`, no copying of `B`.
    /// 2) Symmetric update (i and j updated together) without scanning j twice.
    /// Uses `split_at_mut` to borrow two distinct `&mut B` safely.
    pub fn build_lists_symmetric_no_unsafe(&mut self) {
        let n = self.elems.len();
        let cutoff = self.cutoff;

        for b in &mut self.elems {
            b.nb.clear();
        }

        for i in 0..n {
            for j in (i + 1)..n {
                let (left, right) = self.elems.split_at_mut(j);
                let bi: &mut B = &mut left[i];
                let bj: &mut B = &mut right[0];

                if bi.criterion(bj) < cutoff {
                    bi.nb.push(j);
                    bj.nb.push(i);
                }
            }
        }
    }

    /// 3) Parallel version using Rayon, still safe and no raw pointers.
    /// Computes qualifying pairs (i<j) in parallel, then builds adjacency lists.
    pub fn build_lists_parallel_symmetric(&mut self) {
        let n = self.elems.len();
        let cutoff = self.cutoff;

        // Phase 1: compute edges (i, j) with i < j in parallel using only shared reads.
        let edges: Vec<(usize, usize)> = {
            let elems: &[B] = &self.elems;
            (0..n)
                .into_par_iter()
                .map(|i| {
                    let mut local = Vec::new();
                    for j in (i + 1)..n {
                        if elems[i].criterion(&elems[j]) < cutoff {
                            local.push((i, j));
                        }
                    }
                    local
                })
                .reduce(Vec::new, |mut a, mut b| {
                    a.append(&mut b);
                    a
                })
        };

        // Phase 2: build neighbor lists from edges (sequential, but linear in #edges).
        let mut nbs: Vec<Vec<usize>> = vec![Vec::new(); n];
        for (i, j) in edges {
            nbs[i].push(j);
            nbs[j].push(i);
        }

        // Phase 3: write them back.
        for (b, nb) in self.elems.iter_mut().zip(nbs) {
            b.nb = nb;
        }
    }

    /// Alternative parallel approach (simpler, but does full scan for each i):
    /// each thread only writes to its own `nb[i]` so there's no contention.
    pub fn build_lists_parallel_full_scan(&mut self) {
        let n = self.elems.len();
        let cutoff = self.cutoff;

        let nbs: Vec<Vec<usize>> = {
            let elems: &[B] = &self.elems;
            (0..n)
                .into_par_iter()
                .map(|i| {
                    let mut nb_i = Vec::new();
                    for j in 0..n {
                        if i == j {
                            continue;
                        }
                        if elems[i].criterion(&elems[j]) < cutoff {
                            nb_i.push(j);
                        }
                    }
                    nb_i
                })
                .collect()
        };

        for (b, nb) in self.elems.iter_mut().zip(nbs) {
            b.nb = nb;
        }
    }
}

fn make_b(x: f64, y: f64, z: f64) -> B {
    B {
        r: vec![x, y, z],
        v: vec![0.0, 0.0, 0.0],
        f: vec![0.0, 0.0, 0.0],
        nb: Vec::new(),
    }
}

fn main() {
    let mut a = A {
        elems: vec![
            make_b(0.0, 0.0, 0.0),
            make_b(0.1, 0.0, 0.0),
            make_b(2.0, 0.0, 0.0),
            make_b(0.0, 0.2, 0.0),
        ],
        cutoff: 0.25, // squared distance cutoff
    };

    println!("Initial: {:?}", a.elems.iter().map(|b| &b.r).collect::<Vec<_>>());

    a.build_lists_symmetric_no_unsafe();
    println!("\nSafe symmetric (split_at_mut):");
    for (i, b) in a.elems.iter().enumerate() {
        println!("  {i}: nb = {:?}", b.nb);
    }

    a.build_lists_parallel_symmetric();
    println!("\nParallel symmetric (pairs then build):");
    for (i, b) in a.elems.iter().enumerate() {
        println!("  {i}: nb = {:?}", b.nb);
    }

    a.build_lists_parallel_full_scan();
    println!("\nParallel full-scan (for reference):");
    for (i, b) in a.elems.iter().enumerate() {
        println!("  {i}: nb = {:?}", b.nb);
    }
}
"
}
